value.initial_release:
={{
(
  $('Loop Over Items').item.json.apps.release_date 
    ? $('Loop Over Items').item.json.apps.release_date 
    : ($('Loop Over Items').item.json.apps.country_release_date 
        ? $('Loop Over Items').item.json.apps.country_release_date 
        : $('Loop Over Items').item.json.apps.updated_date)
).split('T')[0]
}}

parameters.query:
UPDATE game_info
SET update_metadata = $1::jsonb
WHERE game_id = $2;

options.queryReplacement:
={{[
({
  updates: [
    {
      version: $('Split Out').item.json.apps.version ?? '',
      updated_date: $json.initial_release
        ? $json.initial_release.toDateTime().format('yyyy-MM-dd')
        : null,
      notes: 'Initial Releases',
      drive_id: '',
      youtube_id: $json.youtube_id ?? ''
    }
  ]
}),
$json.game_id
]}}

parameters.messageJson:
={{
{
  "cardsV2": [
    {
      "cardId": "error-card",
      "card": {
        "header": {
          "title": "WORKFLOW EXECUTION ERROR 🚨",
          "subtitle": "<b>" + $json.workflow.name + " (ID: " + $json.workflow.id + ")</b>"
        },
        "sections": [
          {
            "widgets": [
              {
                "decoratedText": {
                  "topLabel": "Execution",
                  "text": "ID: " + $json.execution.id + " | Retry Of: " + ($json.execution.retryOf || '') + " | Mode: " + $json.execution.mode
                }
              },
              {
                "decoratedText": {
                  "topLabel": "Last Node",
                  "text": "<b>" + $json.execution.lastNodeExecuted + "</b>"
                }
              },
              {
                "decoratedText": {
                  "topLabel": "Error Message",
                  "text": "<b>" + $json.execution.error.message + "</b>"
                }
              },
              {
                "textParagraph": {
                  "text": "<b>" + ($json.execution.error.description || '') + "</b>"
                }
              },
              {
                "buttonList": {
                  "buttons": [
                    {
                      "text": "View Execution Details",
                      "onClick": {
                        "openLink": {
                          "url": $json.execution.url
                        }
                      }
                    }
                  ]
                }
              }
            ]
          }
        ]
      }
    }
  ]
}
}}

